INSERT INTO public.ejes_tematicos (id, tipo_saber_id, clave, nombre, descripcion, orden, created_at, materia_id, periodo_numero) VALUES (810, 2, 'ESP_G4_T2_01', 'Tipos de textos: expositivos, narrativos y descriptivos', 'Utilizar diferentes tipos de textos (expositivos, narrativos y descriptivos), que sirvan como modelo para diversos propósitos en la producción textual oral y escrita (noticias, el periódico, recados, instrucciones, cuentos, adivinanzas,...', 61, '2026-05-30 06:31:36.789663+00', 2, 2);
INSERT INTO public.ejes_tematicos (id, tipo_saber_id, clave, nombre, descripcion, orden, created_at, materia_id, periodo_numero) VALUES (839, 2, 'ESP_G5_T1_08', 'Estrategias de exposición oral (resumir, repetir, resaltar ideas clave)', 'Aplicar estrategias de exposición oral (resumir, repetir, resaltar las ideas para la comprensión textual) por parte de los interlocutores.', 78, '2026-05-30 06:31:36.791924+00', 2, 1);
INSERT INTO public.ejes_tematicos (id, tipo_saber_id, clave, nombre, descripcion, orden, created_at, materia_id, periodo_numero) VALUES (847, 2, 'ESP_G5_T2_05', 'Géneros literarios (poesía, cuento, novela, drama, leyenda)', 'Utilizar estrategias de reconocimiento de los diversos géneros literarios (poesía, cuento, novela, drama, leyenda) e identificación del lenguaje figurado en: adivinanzas, trabalenguas, bombas, refranes, frases célebres y dichos populares para la...', 80, '2026-05-30 06:31:36.793056+00', 2, 2);
INSERT INTO public.ejes_tematicos (id, tipo_saber_id, clave, nombre, descripcion, orden, created_at, materia_id, periodo_numero) VALUES (871, 2, 'ESP_G6_T1_07', 'Tipos de lenguaje: coloquial, meta, formal y figurado', 'Aplicar los diferentes tipos de lenguaje (coloquial o cotidiano, meta, formal y figurado) para el enriquecimiento de las producciones de diversos tipos de texto oral y escrito.', 91, '2026-05-30 06:31:36.795389+00', 2, 1);
INSERT INTO public.ejes_tematicos (id, tipo_saber_id, clave, nombre, descripcion, orden, created_at, materia_id, periodo_numero) VALUES (882, 2, 'ESP_G6_T2_07', 'Géneros literarios (poesía, cuento, novela, drama, leyenda)', 'Utilizar estrategias de reconocimiento de los diversos géneros literarios (poesía, cuento, novela, drama, leyenda) para la comprensión global de los textos. Identificación del lenguaje figurado presente en: adivinanzas, trabalenguas, bombas,...', 97, '2026-05-30 06:31:36.796519+00', 2, 2);
INSERT INTO public.ejes_tematicos (id, tipo_saber_id, clave, nombre, descripcion, orden, created_at, materia_id, periodo_numero) VALUES (893, 2, 'ESP_G6_T3_07', 'Estrategias de comprensión lectora (resúmenes, esquemas, mapas conceptuales)', 'Aplicar estrategias de comprensión lectora (resúmenes, esquemas, síntesis, mapas conceptuales, gráficos, figuras, mapas pictóricos e historietas gráficas, líneas del tiempo, entre otros) en diversos tipos de textos.', 103, '2026-05-30 06:31:36.797875+00', 2, 3);
